export function initializeStoredResourceLayout(rootSelector, storageKey) {
  const root = document.querySelector(rootSelector);
  if (!root) {
    return;
  }

  const layoutLinks = Array.from(
    root.querySelectorAll('[data-resource-layout-link]'),
  );
  if (layoutLinks.length === 0) {
    return;
  }

  const allowedLayouts = new Set(['cards', 'list']);
  const currentUrl = new URL(window.location.href);
  const currentLayout = currentUrl.searchParams.get('layout');

  if (allowedLayouts.has(currentLayout || '')) {
    window.localStorage.setItem(storageKey, currentLayout);
  } else {
    const storedLayout = window.localStorage.getItem(storageKey) || '';
    if (allowedLayouts.has(storedLayout) && storedLayout !== 'cards') {
      currentUrl.searchParams.set('layout', storedLayout);
      window.location.replace(currentUrl.toString());
      return;
    }
  }

  for (const link of layoutLinks) {
    link.addEventListener('click', () => {
      const nextLayout = link.getAttribute('data-resource-layout-link') || '';
      if (!allowedLayouts.has(nextLayout)) {
        return;
      }

      window.localStorage.setItem(storageKey, nextLayout);
    });
  }
}
